import{_ as t,o as e,c as r,a2 as o}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"F04: 業外收支純度與收益質量 — 投資研究員審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/8074_鉅橡/20260501/F04_業外收支純度與收益質量_投資研究員.md","filePath":"審計報告庫/財務審計/8074_鉅橡/20260501/F04_業外收支純度與收益質量_投資研究員.md"}'),n={name:"審計報告庫/財務審計/8074_鉅橡/20260501/F04_業外收支純度與收益質量_投資研究員.md"};function i(l,a,s,h,c,_){return e(),r("div",null,[...a[0]||(a[0]=[o('<p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p><h1 id="f04-業外收支純度與收益質量-—-投資研究員審計報告" tabindex="-1">F04: 業外收支純度與收益質量 — 投資研究員審計報告 <a class="header-anchor" href="#f04-業外收支純度與收益質量-—-投資研究員審計報告" aria-label="Permalink to &quot;F04: 業外收支純度與收益質量 — 投資研究員審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>業外收支 (Non-Operating) 規模與組成細項為何？是長期投資收益還是匯兌/利息等雜項損益？是否存在獲利虛胖風險？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>根據截至 2025 年第四季最新數據，鉅橡業外收入佔淨利約 47%，其中匯兌利益佔業外總額 70% 以上。本業獲利純度中等，評價應採保守觀點。風險評級：中。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>業外結構</strong>：利息收入約 580 萬～646 萬 TWD，匯兌利益 1,490 萬～2,398 萬 TWD（佔業外 70-80%），金融資產損益 ±141 萬～358 萬 TWD，無權益法投資。</li><li><strong>淨利貢獻比</strong>：業外/淨利 2.5%～67.3%，全年約 47%。</li><li><strong>評級</strong>：B（持平）。獲利高度依賴匯兌利益，淨利受外幣波動。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="一、收益結構透視-業外三大組成拆解" tabindex="-1">一、收益結構透視：業外三大組成拆解 <a class="header-anchor" href="#一、收益結構透視-業外三大組成拆解" aria-label="Permalink to &quot;一、收益結構透視：業外三大組成拆解&quot;">​</a></h3><p><strong>利息收入</strong>：112 年度 2,177 萬 → 114 年度 575 萬 TWD，逐年萎縮反映現金部位或存款利率下降。</p><p><strong>匯兌利益（淨外幣兌換利益）</strong>：112 年度 1,782 萬 → 113 年度 2,399 萬 → 114 年度 1,491 萬 TWD，佔業外總額 70-80%，為絕對主力。此項具高度隨機性，隨台幣/美金匯率波動而反轉。</p><p><strong>金融資產損益</strong>：113 年度 -358 萬（損失）→ 114 年度 +141 萬（利益），強制透過損益按公允價值衡量，規模有限但方向不確定。</p><p><strong>權益法投資</strong>：三年均無此項目，公司未持有具重大影響力之被投資公司。</p><h3 id="二、雜訊敏感度分析-匯率風險暴露" tabindex="-1">二、雜訊敏感度分析：匯率風險暴露 <a class="header-anchor" href="#二、雜訊敏感度分析-匯率風險暴露" aria-label="Permalink to &quot;二、雜訊敏感度分析：匯率風險暴露&quot;">​</a></h3><p>以 114 年度數據為基準，淨利 4,456 萬 TWD 中約 2,094 萬來自業外，其中匯兌利益佔 1,491 萬。若台幣升值 5%，淨利可能減少 700 萬～1,200 萬 TWD，相當於當年度淨利的 16-27%。此敏感度已觸發「獲利含金量極低」警訊標準（匯兌佔比 &gt; 25%）。</p><h3 id="三、可持續性評價" tabindex="-1">三、可持續性評價 <a class="header-anchor" href="#三、可持續性評價" aria-label="Permalink to &quot;三、可持續性評價&quot;">​</a></h3><ul><li><strong>利息收入</strong>：常態性再現機率高，但規模不足以支撐 EPS。</li><li><strong>匯兌利益</strong>：不可持續。隨匯率週期反轉，113 年度 +2,399 萬 → 114 年度 +1,491 萬，方向已轉弱。</li><li><strong>金融資產損益</strong>：不可預測，無常態性再現基礎。</li><li><strong>綜合判定</strong>：未來三季內業外收入具備「低常態性再現」機率，淨利預測應以本業為基準。</li></ul><h2 id="💡-專家評析-skepticism-mandate" tabindex="-1">💡 專家評析 (Skepticism Mandate) <a class="header-anchor" href="#💡-專家評析-skepticism-mandate" aria-label="Permalink to &quot;💡 專家評析 (Skepticism Mandate)&quot;">​</a></h2><ul><li><strong>空頭風險一：匯兌利益反轉吞噬本業獲利。</strong> 114 年度淨利 4,456 萬 TWD，若剔除業外 2,094 萬（其中匯兌 1,491 萬），本業稅前淨利僅約 3,365 萬。一旦台幣進入升值週期，匯兌利益轉為損失，淨利可能腰斬。此風險已觸發 &gt;25% 含金量警訊標準。</li><li><strong>空頭風險二：利息收入萎縮趨勢無止損。</strong> 利息收入從 112 年度 2,177 萬降至 114 年度 575 萬，降幅 73%。反映公司現金管理效率下降或存款結構惡化。若利率環境反轉下行，利息收入將進一步萎縮，業外收入結構將更加脆弱。</li><li><strong>公允價值風險預警</strong>：金融資產雖僅 ±141 萬～358 萬，但屬「強制透過損益按公允價值衡量」，市場波動時未實現評價可能瞬間轉為巨大減損。此科目無對沖機制，應列為潛在黑天鵂風險。</li></ul><h2 id="📚-證據來源-veracity-check" tabindex="-1">📚 證據來源 (Veracity Check) <a class="header-anchor" href="#📚-證據來源-veracity-check" aria-label="Permalink to &quot;📚 證據來源 (Veracity Check)&quot;">​</a></h2><ul><li><strong>FinMind</strong>: OK — TaiwanStockFinancialStatements，查詢參數：stock_id=8074, start=2023-01-01, end=2025-12-31，提取 TotalNonoperatingIncomeAndExpense、OTHNOE、Revenue、GrossProfit、OperatingIncome、IncomeAfterTaxes 等欄位。</li><li><strong>年報 PDF</strong>: OK — 鉅橡企業 114 年度合併財務報告（頁碼 9、44-45，附註二四稅前淨利明細）、113 年度合併財務報告（頁碼 40-41，附註二二稅前淨利明細）、112 年度合併財務報告（頁碼 40-41）。</li><li><strong>關鍵核對碼</strong>：114 年度業外合計 20,939 千元 = 利息收入 5,753 + 淨外幣兌換利益 14,905 + 金融資產損益 1,414 + 其他利益及損失淨額 -1,133（含投資性不動產折舊 203 + 太陽光電折舊 1,781 + 應收增值稅退稅款轉列損失 6,271 等）。</li></ul>',22)])])}const u=t(n,[["render",i]]);export{g as __pageData,u as default};
